 public function __construct(protected ?array $config=null,protected ?PositionStateEvaluationService $stateService=null,protected ?PositionManagementPolicyService $policyService=null,protected ?PositionManagementCandidateService $candidateService=null,protected ?PositionManagementSelectionService $selectionService=null,protected ?PositionManagementRiskEvaluationService $riskService=null,protected ?PositionManagementReviewPlanService $reviewPlanService=null){$this->config??=config('trading_position_management');$this->stateService??=new PositionStateEvaluationService($this->config);$this->policyService??=new PositionManagementPolicyService();$this->candidateService??=new PositionManagementCandidateService();$this->selectionService??=new PositionManagementSelectionService();$this->riskService??=new PositionManagementRiskEvaluationService();$this->reviewPlanService??=new PositionManagementReviewPlanService();}
 public function evaluate(array $ctx):array{$scope=$ctx['decision_scope']??'entry_evaluation';$state=$ctx['position_state']??($scope==='position_management'?$this->stateService->evaluate($ctx):null);$policyEval=$scope==='position_management'?$this->policyService->evaluate($ctx+['position_state'=>$state]):$this->emptyPolicyEvaluation($state);$candidate=$scope==='position_management'?$this->candidateService->form($ctx+['position_state'=>$state,'policy_evaluation'=>$policyEval]):$this->emptyCandidate($state,$policyEval);$risk=$scope==='position_management'?$this->riskService->evaluate($ctx+['position_state'=>$state,'policy_evaluation'=>$policyEval,'management_candidate'=>$candidate]):$this->emptyRisk($state,$candidate);$reviewPlan=$scope==='position_management'?$this->reviewPlanService->build($ctx+['position_state'=>$state,'policy_evaluation'=>$policyEval,'management_candidate'=>$candidate,'management_risk'=>$risk]):$this->emptyReviewPlan($candidate,$risk);$selection=$scope==='position_management'?$this->selectionService->select($ctx+['position_state'=>$state,'policy_evaluation'=>$policyEval,'management_candidate'=>$candidate,'management_risk'=>$risk,'review_plan'=>$reviewPlan]):$this->emptySelection($candidate);$codes=[];$warnings=[];$blockers=[];if($scope!=='position_management'){$this->add($codes,'POSITION_MANAGEMENT_NOT_REQUIRED');$status='not_required';$elig='not_required';}elseif(!is_array($state)||($state['status']??null)==='unavailable'){$this->add($codes,'POSITION_MANAGEMENT_UNAVAILABLE',$blockers);$status='unavailable';$elig='position_state_unavailable';}else{$status=($state['status']==='condition_observed')?'condition_observed':(($state['status']==='partial')?'partial':'monitoring_reference');$elig=$status;$this->add($codes,'POSITION_MANAGEMENT_REFERENCE_MONITORING_AVAILABLE');$this->add($codes,'POSITION_MANAGEMENT_ACTION_NOT_IMPLEMENTED',$blockers);$this->add($codes,'POSITION_MANAGEMENT_EXECUTION_NOT_IMPLEMENTED',$blockers);if($status==='condition_observed')$this->add($codes,'POSITION_MANAGEMENT_CONDITION_OBSERVED',$blockers);}foreach([$policyEval,$candidate,$selection] as $part){foreach($part['reason_codes']??[] as $c)$this->add($codes,$c);foreach($part['warnings']??[] as $c)$this->add($warnings,$c);foreach($part['blockers']??[] as $c)$this->add($blockers,$c);}foreach(['HOLD_ACTION_NOT_IMPLEMENTED','EXIT_ACTION_NOT_IMPLEMENTED','CUT_LOSS_ACTION_NOT_IMPLEMENTED','POSITION_MANAGEMENT_NON_EXECUTABLE'] as $c)$this->add($codes,$c,$blockers);$r=['schema_version'=>$this->config['position_management_schema_version'],'status'=>$status,'position_id'=>$state['position_id']??null,'ticker'=>$state['ticker']??null,'management_scope'=>'reference_non_executable','eligibility'=>$elig,'position_state'=>$state??[],'policy_evaluation'=>$policyEval,'management_candidate'=>$candidate,'management_risk'=>$risk,'review_plan'=>$reviewPlan,'management_selection'=>$selection,'management_readiness'=>['status'=>$status==='not_required'?'unavailable':(($status==='condition_observed')?'condition_observed':'monitoring_ready'),'state_monitoring'=>$state['status']??'unavailable','policy_evaluation'=>$policyEval['status']??'unavailable','candidate'=>$candidate['status']??'unavailable','management_risk'=>$risk['status']??'unavailable','review_plan'=>$reviewPlan['status']??'unavailable','action_selection'=>'not_implemented','execution'=>'not_implemented'],'management_action_candidate'=>null,'selected_management_action'=>null,'promoted_management_action'=>null,'executable_instruction'=>null,'approved'=>false,'reason_codes'=>$this->ordered($codes),'warnings'=>$this->ordered($warnings),'blockers'=>$this->ordered($blockers),'metadata'=>['non_executable'=>true]];$this->validatePositionManagement($r);return $r;}
 public function validatePositionManagement($r):void{if(($r['schema_version']??null)!==$this->config['position_management_schema_version'])throw new \InvalidArgumentException('bad pm schema');if(($r['management_action_candidate']??null)!==null||($r['selected_management_action']??null)!==null||($r['promoted_management_action']??null)!==null||($r['executable_instruction']??null)!==null||($r['approved']??null)!==false)throw new \InvalidArgumentException('pm executable disabled');if(count($r['reason_codes'])!==count(array_unique($r['reason_codes'])))throw new \InvalidArgumentException('duplicate pm reasons');}
